'use client'

import { useState, useRef, useEffect } from 'react'
import ReactMarkdown from 'react-markdown'
import remarkGfm from 'remark-gfm'
import { generateUserId } from '@/lib/utils'
import ContactForm from '@/components/contact-form'
import Image from 'next/image'

interface Message {
  id: string
  type: 'user' | 'bot'
  content: string
  timestamp: Date
  showForm?: boolean
}

interface UserChatProps {
  onBack: () => void
}

export default function UserChat({ onBack }: UserChatProps) {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      type: 'bot',
      content: "Welcome to The Cincinnatian Hotel. I'm your personal concierge. How can I assist you today? Feel free to ask about our rooms, amenities, dining, or anything about your stay.",
      timestamp: new Date(),
    },
  ])
  const [input, setInput] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [userId, setUserId] = useState<string>('')
  const messagesEndRef = useRef<HTMLDivElement>(null)

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }

  useEffect(() => {
    scrollToBottom()
  }, [messages])

  useEffect(() => {
    setUserId(generateUserId())
  }, [])

  const isFallbackResponse = (response: any): boolean => {
    const exactFallbackMessage = "I dont have prior information about the topic you are asking. I apologize for the inconvenience. To ensure you get the correct answer, please provide your Name, Phone Number, and Email, using the form below and a representative will contact you shortly."

    if (typeof response === 'string') {
      return response.trim() === exactFallbackMessage
    }

    if (response && typeof response === 'object') {
      if (response.fallback === true) return true
      if (response.output && typeof response.output === 'string') {
        return response.output.trim() === exactFallbackMessage
      }
    }

    return false
  }

  const handleContactSubmit = async (data: { name: string; phone: string; email: string }) => {
    try {
      const response = await fetch('/api/submit-contact-info', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId, ...data }),
      })
      if (!response.ok) throw new Error('Failed to submit contact information')
    } catch (error) {
      console.error('Error submitting contact form:', error)
      throw error
    }
  }

  const handleSendMessage = async () => {
    if (!input.trim() || isLoading) return

    const userMessage: Message = {
      id: Date.now().toString(),
      type: 'user',
      content: input,
      timestamp: new Date(),
    }

    setMessages((prev) => [...prev, userMessage])
    setInput('')
    setIsLoading(true)

    try {
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId,
          message: userMessage.content,
          timestamp: userMessage.timestamp.toISOString(),
        }),
      })

      const data = await response.json()

      if (response.ok && data.success) {
        let botContent: string
        let showForm = false

        if (typeof data.response === 'string') {
          botContent = data.response
          showForm = isFallbackResponse(data.response)
        } else if (data.response && typeof data.response === 'object') {
          if (Array.isArray(data.response) && data.response.length > 0 && data.response[0].output) {
            botContent = data.response[0].output.output
            showForm = isFallbackResponse(data.response[0].output)
          } else {
            botContent = data.response.output || data.response.message || JSON.stringify(data.response)
            showForm = isFallbackResponse(data.response)
          }
        } else {
          botContent = "I'm sorry, I couldn't process your request. Please try again."
        }

        setMessages((prev) => [...prev, {
          id: (Date.now() + 1).toString(),
          type: 'bot',
          content: botContent,
          timestamp: new Date(),
          showForm,
        }])
      } else {
        setMessages((prev) => [...prev, {
          id: (Date.now() + 1).toString(),
          type: 'bot',
          content: "I'm sorry, I'm having trouble connecting right now. Please try again.",
          timestamp: new Date(),
        }])
      }
    } catch (error) {
      console.error('Error sending message:', error)
      setMessages((prev) => [...prev, {
        id: (Date.now() + 1).toString(),
        type: 'bot',
        content: "I'm sorry, I'm having trouble connecting right now. Please try again.",
        timestamp: new Date(),
      }])
    } finally {
      setIsLoading(false)
    }
  }

  const handleRefresh = () => {
    setUserId(generateUserId())
    setMessages([{
      id: '1',
      type: 'bot',
      content: "Welcome to The Cincinnatian Hotel. I'm your personal concierge. How can I assist you today? Feel free to ask about our rooms, amenities, dining, or anything about your stay.",
      timestamp: new Date(),
    }])
    setInput('')
    setIsLoading(false)
  }

  const handleBack = () => {
    setUserId(generateUserId())
    onBack()
  }

  return (
    <div
      className="relative min-h-screen bg-cover bg-center overflow-hidden flex flex-col"
      style={{ backgroundImage: `url('/background.jpg')` }}
    >
      {/* Dark overlay */}
      <div className="absolute inset-0 bg-black/70" />
      <div className="absolute inset-0 bg-gradient-to-b from-black/40 via-transparent to-black/60" />

      {/* Header — glass with gold bottom accent */}
      <header className="fixed top-0 left-0 right-0 z-50 backdrop-blur-xl bg-black/55 border-b border-white/8">
        {/* Gold accent line at very bottom */}
        <div className="absolute bottom-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-primary/35 to-transparent" />
        <div className="flex items-center justify-between px-6 sm:px-10 py-4">
          <div className="flex items-center gap-3">
            <Image
              src="/hotel-logo.png"
              alt="Cincinnati Hotel"
              width={22}
              height={22}
              className="opacity-80"
            />
            <span className="label-caps text-foreground/70">Cincinnati Hotel</span>
            <span className="label-caps text-primary/50 hidden sm:block">· Concierge</span>
          </div>
          <div className="flex items-center gap-5">
            <button
              onClick={handleRefresh}
              className="label-caps text-foreground/35 hover:text-primary/70 transition-colors duration-300"
            >
              Refresh
            </button>
            <button
              onClick={handleBack}
              className="label-caps text-foreground/35 hover:text-primary/70 transition-colors duration-300"
            >
              ← Back
            </button>
          </div>
        </div>
      </header>

      {/* Messages area */}
      <main className="relative z-10 flex-1 overflow-y-auto custom-scrollbar pt-20 pb-28 px-4 sm:px-6">
        <div className="max-w-2xl mx-auto py-8 space-y-6">
          {messages.map((message) => (
            <div
              key={message.id}
              className={`flex ${message.type === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div className={`flex flex-col gap-1.5 max-w-[80%] ${message.type === 'user' ? 'items-end' : 'items-start'}`}>
                <span className="label-caps text-foreground/30 px-1">
                  {message.type === 'user' ? 'You' : 'Concierge'}
                </span>
                <div
                  className={`px-4 py-3.5 rounded-2xl font-light leading-relaxed text-sm chat-message backdrop-blur-sm ${
                    message.type === 'user'
                      ? 'bg-primary/20 border border-primary/35 text-foreground rounded-br-sm shadow-lg shadow-primary/5'
                      : 'bg-black/55 border border-white/12 text-foreground/90 rounded-bl-sm'
                  }`}
                >
                  <div className="markdown-content">
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>{message.content}</ReactMarkdown>
                  </div>
                </div>

                {message.showForm && (
                  <div className="mt-3 w-full bg-black/50 backdrop-blur-xl border border-white/10 rounded-2xl p-5">
                    <ContactForm onSubmit={handleContactSubmit} />
                  </div>
                )}
              </div>
            </div>
          ))}

          {isLoading && (
            <div className="flex justify-start">
              <div className="flex flex-col items-start gap-1.5">
                <span className="label-caps text-foreground/30 px-1">Concierge</span>
                <div className="px-4 py-3.5 rounded-2xl rounded-bl-sm bg-black/55 border border-white/12 backdrop-blur-sm">
                  <div className="flex gap-1.5 items-center">
                    <div className="w-1.5 h-1.5 rounded-full bg-primary/60 animate-bounce [animation-delay:-0.3s]" />
                    <div className="w-1.5 h-1.5 rounded-full bg-primary/60 animate-bounce [animation-delay:-0.15s]" />
                    <div className="w-1.5 h-1.5 rounded-full bg-primary/60 animate-bounce" />
                  </div>
                </div>
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>
      </main>

      {/* Input bar — glass panel with gold top accent */}
      <footer className="fixed bottom-0 left-0 right-0 z-50 backdrop-blur-xl bg-black/60 border-t border-white/8">
        {/* Gold top accent */}
        <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-primary/35 to-transparent" />
        <div className="max-w-2xl mx-auto px-6 sm:px-10 py-4 flex items-center gap-4">
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && handleSendMessage()}
            disabled={isLoading}
            placeholder="Ask anything about your stay..."
            className="flex-1 bg-white/5 border border-white/12 focus:border-primary/40 rounded-xl px-4 py-2.5 text-foreground font-light text-sm placeholder:text-foreground/25 outline-none transition-all duration-300 disabled:opacity-40"
          />
          <button
            onClick={handleSendMessage}
            disabled={isLoading || !input.trim()}
            className="bg-primary/85 hover:bg-primary text-black font-medium text-xs tracking-wide px-4 py-2.5 rounded-xl transition-all duration-300 disabled:opacity-30 disabled:cursor-not-allowed"
          >
            Send
          </button>
        </div>
      </footer>
    </div>
  )
}
