'use client'

import { useState, useRef } from 'react'
import Image from 'next/image'
import ChatAnalyticsChart from '@/components/ChatAnalyticsChart'

interface AdminDashboardProps {
  onBack: () => void
}

export default function AdminDashboard({ onBack }: AdminDashboardProps) {
  const fileInputRef = useRef<HTMLInputElement>(null)
  const [selectedFile, setSelectedFile] = useState<File | null>(null)
  const [isUploading, setIsUploading] = useState(false)
  const [uploadStatus, setUploadStatus] = useState<{ message: string; success: boolean } | null>(null)

  const handleUpload = async () => {
    if (!selectedFile) return
    setIsUploading(true)
    setUploadStatus(null)

    const formData = new FormData()
    formData.append('file', selectedFile)

    try {
      const response = await fetch('/api/admin/upload-hotel-info', {
        method: 'POST',
        body: formData,
      })
      const result = await response.json()

      if (response.ok) {
        setUploadStatus({ message: 'File uploaded successfully', success: true })
        setSelectedFile(null)
        if (fileInputRef.current) fileInputRef.current.value = ''
      } else {
        setUploadStatus({ message: result.error || 'Upload failed', success: false })
      }
    } catch (error) {
      console.error('Upload error:', error)
      setUploadStatus({ message: 'Upload failed. Please try again.', success: false })
    } finally {
      setIsUploading(false)
    }
  }

  return (
    <div className="min-h-screen relative">
      {/* Background */}
      <div className="absolute inset-0 z-0">
        <Image
          src="/background.jpg"
          alt="Cincinnati Hotel"
          fill
          className="object-cover"
          priority
          quality={90}
        />
        <div className="absolute inset-0 bg-black/75" />
        <div className="absolute inset-0 bg-gradient-to-b from-black/50 via-transparent to-black/60" />
      </div>

      <div className="relative z-10 flex flex-col min-h-screen">

        {/* Header — glass with gold accent */}
        <header className="sticky top-0 z-50 backdrop-blur-xl bg-black/60 border-b border-white/8">
          <div className="absolute bottom-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-primary/35 to-transparent" />
          <div className="flex items-center justify-between px-8 sm:px-12 py-4">
            <div className="flex items-center gap-3">
              <Image
                src="/hotel-logo.png"
                alt="Cincinnati Hotel"
                width={24}
                height={24}
                className="opacity-80"
              />
              <span className="label-caps text-foreground/70">Cincinnati Hotel</span>
              <span className="label-caps text-primary/50 hidden sm:block">· Admin</span>
            </div>
            <button
              onClick={onBack}
              className="label-caps text-foreground/35 hover:text-primary/70 transition-colors duration-300"
            >
              ← Exit
            </button>
          </div>
        </header>

        {/* Content */}
        <main className="flex-1 max-w-4xl mx-auto w-full px-8 sm:px-12 py-10 sm:py-14 space-y-10">

          {/* Upload card */}
          <section className="rounded-2xl overflow-hidden backdrop-blur-xl bg-black/50 border border-white/10 shadow-2xl shadow-black/40">
            {/* Gold top stripe */}
            <div className="h-px bg-gradient-to-r from-transparent via-primary/50 to-transparent" />

            <div className="p-7 sm:p-9">
              <div className="flex items-center gap-3 mb-1">
                <div className="w-1 h-4 bg-primary/70 rounded-full" />
                <p className="label-caps text-primary/70">Document Management</p>
              </div>
              <h2 className="text-xl font-light text-foreground mb-5 pl-4">Hotel Information</h2>

              <p className="text-foreground/45 font-light text-sm mb-7 max-w-lg pl-4">
                Upload a PDF containing your hotel's information. This serves as the knowledge base for the AI concierge. A new upload replaces the previous file.
              </p>

              <input
                type="file"
                accept=".pdf"
                ref={fileInputRef}
                className="hidden"
                onChange={(e) => {
                  if (e.target.files && e.target.files[0]) {
                    setSelectedFile(e.target.files[0])
                    setUploadStatus(null)
                  }
                }}
              />

              {/* Upload zone */}
              <div
                onClick={() => fileInputRef.current?.click()}
                className="border border-dashed border-white/15 hover:border-primary/40 rounded-xl p-10 sm:p-12 text-center cursor-pointer hover:bg-primary/[0.03] transition-all duration-500 max-w-lg"
              >
                <div className="w-10 h-10 rounded-full border border-primary/30 flex items-center justify-center mx-auto mb-4">
                  <span className="text-primary/60 text-lg leading-none">↑</span>
                </div>
                <p className="label-caps text-foreground/40 mb-2">PDF only · Max 50 MB</p>
                {selectedFile ? (
                  <p className="text-primary font-light text-sm mt-3">{selectedFile.name}</p>
                ) : (
                  <p className="text-foreground/35 font-light text-sm">Drag here or click to browse</p>
                )}
              </div>

              {selectedFile && (
                <div className="mt-5 flex items-center gap-6 pl-1">
                  <button
                    onClick={handleUpload}
                    disabled={isUploading}
                    className="bg-primary/85 hover:bg-primary text-black font-medium text-xs tracking-wide px-5 py-2 rounded-lg transition-all duration-300 disabled:opacity-30 disabled:cursor-not-allowed flex items-center gap-2"
                  >
                    {isUploading ? (
                      <>
                        <span className="w-3 h-3 border border-black border-t-transparent rounded-full animate-spin" />
                        Uploading...
                      </>
                    ) : 'Upload File'}
                  </button>
                  <button
                    onClick={() => {
                      setSelectedFile(null)
                      if (fileInputRef.current) fileInputRef.current.value = ''
                    }}
                    disabled={isUploading}
                    className="label-caps text-foreground/30 hover:text-foreground/55 transition-colors duration-300 disabled:opacity-30"
                  >
                    Clear
                  </button>
                </div>
              )}

              {uploadStatus && (
                <p className="label-caps mt-5 flex items-center gap-2 pl-1">
                  <span className={`inline-block w-1.5 h-1.5 rounded-full flex-shrink-0 ${uploadStatus.success ? 'bg-emerald-400' : 'bg-red-400'}`} />
                  <span className={uploadStatus.success ? 'text-emerald-400/80' : 'text-red-400/80'}>
                    {uploadStatus.message}
                  </span>
                </p>
              )}
            </div>
          </section>

          {/* Analytics card */}
          <section className="rounded-2xl overflow-hidden backdrop-blur-xl bg-black/50 border border-white/10 shadow-2xl shadow-black/40">
            <div className="h-px bg-gradient-to-r from-transparent via-primary/50 to-transparent" />

            <div className="p-7 sm:p-9">
              <div className="flex items-center gap-3 mb-1">
                <div className="w-1 h-4 bg-primary/70 rounded-full" />
                <p className="label-caps text-primary/70">Insights</p>
              </div>
              <h2 className="text-xl font-light text-foreground mb-7 pl-4">Chat Statistics</h2>

              <ChatAnalyticsChart />
            </div>
          </section>

        </main>
      </div>
    </div>
  )
}
